body.script:
(function(){
  let lastPlayerId = null;
  let lastState    = null;

  function fmtPts(n) {
    if (!n) return '0 pts';
    if (n >= 100000) return (n/100000).toFixed(2).replace(/\.?0+$/,'') + 'L pts';
    if (n >= 1000)   return (n/1000).toFixed(1).replace(/\.?0+$/,'') + 'K pts';
    return n + ' pts';
  }

  function safeImg(url) {
    return url || '';
  }

  // ── Clock ──────────────────────────────────────────────────────
  function updateClock() {
    const now = new Date();
    document.getElementById('lb-clock').textContent =
      now.toLocaleTimeString('en-IN', {hour:'2-digit', minute:'2-digit', second:'2-digit'});
  }
  var _clockTimer = setInterval(updateClock, 1000);
  updateClock();
  window.addEventListener('beforeunload', function() { clearInterval(_clockTimer); });

  // ── Render Player Panel ────────────────────────────────────────
  function renderPlayer(p) {
    if (!p) {
      document.getElementById('lb-pname').textContent = 'Waiting for next player…';
      document.getElementById('lb-psub').textContent = '';
      document.getElementById('lb-photo-ph').style.display = 'flex';
      document.getElementById('lb-player-img').style.display = 'none';
      document.getElementById('lb-sl-overlay').style.display = 'none';
      document.getElementById('lb-state-overlay').style.display = 'none';
      document.getElementById('lb-sold-stamp').style.display   = 'none';
      document.getElementById('lb-unsold-stamp').style.display = 'none';
      document.getElementById('lb-badges-row').innerHTML = '';
      document.getElementById('lb-stats-row').style.display = 'none';
      document.getElementById('lb-base-row').style.display = 'none';
      return;
    }

    // Photo
    const img = document.getElementById('lb-player-img');
    const ph  = document.getElementById('lb-photo-ph');
    if (p.photo_url) {
      img.src = p.photo_url;
      img.style.display = 'block';
      ph.style.display  = 'none';
    } else {
      img.style.display = 'none';
      ph.style.display  = 'flex';
    }

    // Name + sub
    document.getElementById('lb-pname').textContent = p.name || '—';
    document.getElementById('lb-psub').textContent  =
      [p.role, p.tier_name].filter(Boolean).join(' · ');

    // SL badge
    const slEl = document.getElementById('lb-sl-overlay');
    if (p.sl_no) { slEl.style.display = ''; document.getElementById('lb-sl-num').textContent = p.sl_no; }
    else           { slEl.style.display = 'none'; }

    // State overlay
    const stEl = document.getElementById('lb-state-overlay');
    stEl.style.display = '';
    stEl.className = 'lb-state-overlay lb-state-' + (p.state || 'auction');
    stEl.textContent = p.state === 'sold' ? 'SOLD' : p.state === 'unsold' ? 'UNSOLD' : 'LIVE';

    // Sold / Unsold stamp
    const soldStamp   = document.getElementById('lb-sold-stamp');
    const unsoldStamp = document.getElementById('lb-unsold-stamp');
    if (p.state === 'sold' && p.sold_info) {
      soldStamp.style.display  = '';
      unsoldStamp.style.display = 'none';
      // reset animation
      soldStamp.style.animation = 'none';
      soldStamp.offsetHeight; // reflow
      soldStamp.style.animation = '';
      document.getElementById('stamp-pts').textContent = fmtPts(p.sold_info.amount);
      document.getElementById('stamp-team-name').textContent = p.sold_info.team_name || '';
      const logoImg  = document.getElementById('stamp-team-logo');
      const logoWrap = document.getElementById('stamp-team-logo-wrap');
      if (p.sold_info.team_logo_url) {
        logoImg.src = p.sold_info.team_logo_url;
        logoWrap.style.display = '';
      } else {
        logoWrap.style.display = 'none';
      }
      stEl.style.display = 'none'; // stamp replaces the badge
    } else if (p.state === 'unsold') {
      unsoldStamp.style.display = '';
      soldStamp.style.display   = 'none';
      // reset animation
      unsoldStamp.style.animation = 'none';
      unsoldStamp.offsetHeight;
      unsoldStamp.style.animation = '';
      stEl.style.display = 'none'; // stamp replaces the badge
    } else {
      soldStamp.style.display   = 'none';
      unsoldStamp.style.display = 'none';
    }

    // Badges
    let badgesHtml = '';
    if (p.tier_name) {
      badgesHtml += `<span class="lb-badge lb-b-tier" style="background:${p.tier_color || '#2252b5'}">${p.tier_name}</span>`;
    }
    if (p.role) {
      badgesHtml += `<span class="lb-badge lb-b-role">${p.role}</span>`;
    }
    if (p.icon_player) {
      badgesHtml += `<span class="lb-badge lb-b-icon">⭐ Icon</span>`;
    }
    document.getElementById('lb-badges-row').innerHTML = badgesHtml;

    // Batting / Bowling stats
    if (p.batting_style || p.bowling_style) {
      document.getElementById('lb-stats-row').style.display = 'flex';
      document.getElementById('lb-bat-val').textContent  = p.batting_style  || '—';
      document.getElementById('lb-bowl-val').textContent = p.bowling_style || '—';
    } else {
      document.getElementById('lb-stats-row').style.display = 'none';
    }

    // Base price
    if (p.base_price) {
      document.getElementById('lb-base-row').style.display = '';
      document.getElementById('lb-base-val').textContent = fmtPts(p.base_price);
    } else {
      document.getElementById('lb-base-row').style.display = 'none';
    }
  }

  // ── Render Status Card ─────────────────────────────────────────
  function renderStatus(currentPlayer, soldInfo) {
    const card = document.getElementById('lb-status-card');

    if (!currentPlayer) {
      card.innerHTML = `<div class="lb-status-waiting">
        <div class="lb-auction-spinner"></div>
        <div class="lb-auction-pulse">Waiting for auction to begin…</div>
      </div>`;
      return;
    }

    if (currentPlayer.state === 'sold' && soldInfo) {
      const logoHtml = soldInfo.team_logo_url
        ? `<img src="${soldInfo.team_logo_url}" alt="logo" onerror="this.parentElement.innerHTML='🏆'">`
        : '🏆';
      card.innerHTML = `<div class="lb-status-sold">
        <div class="lb-status-label">🏆 Sold!</div>
        <div class="lb-sold-amount">${fmtPts(soldInfo.amount)}</div>
        <div class="lb-sold-team">
          <div class="lb-sold-team-logo">${logoHtml}</div>
          <div>
            <div class="lb-sold-team-name">${soldInfo.team_name}</div>
          </div>
        </div>
      </div>`;
    } else if (currentPlayer.state === 'auction') {
      card.innerHTML = `<div class="lb-status-auction">
        <div class="lb-status-label">🎯 In Auction — Bidding in Progress</div>
        <div style="margin-top:18px; display:flex; align-items:center; gap:12px;">
          <div class="lb-auction-spinner" style="width:20px;height:20px;border-width:3px;"></div>
          <div style="font-size:1.05rem;font-weight:700;color:rgba(255,255,255,0.8);">
            Accepting bids from teams…
          </div>
        </div>
        <div style="margin-top:14px;font-size:.72rem;opacity:.6;">
          Base price: <strong>${fmtPts(currentPlayer.base_price)}</strong>
        </div>
      </div>`;
    } else {
      card.innerHTML = `<div class="lb-status-waiting">
        <div class="lb-auction-spinner"></div>
        <div class="lb-auction-pulse">Loading…</div>
      </div>`;
    }
  }

  // ── Render History ─────────────────────────────────────────────
  function renderHistory(history) {
    const list = document.getElementById('lb-history-list');
    if (!history || !history.length) {
      list.innerHTML = '<div class="lb-history-empty">No transactions yet</div>';
      return;
    }
    list.innerHTML = history.map(h => {
      const avatarHtml = h.team_logo_url
        ? `<img src="${h.team_logo_url}" alt="" onerror="this.parentElement.innerHTML='🏅'">`
        : '<span class="lb-history-avatar-ph">🏅</span>';
      return `<div class="lb-history-item">
        <div class="lb-history-avatar">${avatarHtml}</div>
        <div class="lb-history-msg">${h.message || ''}</div>
        <div class="lb-history-time">${h.timestamp || ''}</div>
      </div>`;
    }).join('');
  }

  // ── Render MVP / Top Buys ──────────────────────────────────────
  function renderTopPlayers(topPlayers) {
    const list = document.getElementById('lb-mvp-list');
    if (!topPlayers || !topPlayers.length) {
      list.innerHTML = '<div class="lb-mvp-empty">No sold players yet</div>';
      return;
    }
    const medals = ['👑', '🥈', '🥉'];
    const rankClasses = ['lb-mvp-rank-gold', 'lb-mvp-rank-silver', 'lb-mvp-rank-bronze', 'lb-mvp-rank-num', 'lb-mvp-rank-num'];
    list.innerHTML = topPlayers.map((p, idx) => {
      const isMvp = idx === 0;
      const rankIcon  = medals[idx] !== undefined ? medals[idx] : String(p.rank);
      const rankClass = rankClasses[idx] || 'lb-mvp-rank-num';
      const avatarHtml = p.player_photo_url
        ? `<img src="${p.player_photo_url}" alt="" onerror="this.style.display='none';this.parentElement.innerHTML='<span class=lb-mvp-avatar-ph>👤</span>'">`
        : '<span class="lb-mvp-avatar-ph">👤</span>';
      const teamLogoHtml = p.team_logo_url
        ? `<div class="lb-mvp-team-logo"><img src="${p.team_logo_url}" alt=""></div>`
        : '';
      return `<div class="lb-mvp-item${isMvp ? ' lb-mvp-item-1' : ''}">
        <div class="lb-mvp-rank ${rankClass}">${rankIcon}</div>
        <div class="lb-mvp-avatar">
          <div class="lb-mvp-avatar-inner">${avatarHtml}</div>
          ${isMvp ? '<div class="lb-mvp-crown">👑</div>' : ''}
        </div>
        <div class="lb-mvp-info">
          <div class="lb-mvp-name">${p.player_name || '—'}</div>
          <div class="lb-mvp-sub">${p.role || ''}</div>
        </div>
        <div class="lb-mvp-right">
          <div class="lb-mvp-pts">${fmtPts(p.points)}</div>
          <div class="lb-mvp-team">
            ${teamLogoHtml}
            <span class="lb-mvp-team-name">${p.team_name || ''}</span>
          </div>
        </div>
      </div>`;
    }).join('');
  }

  // ── Render Teams Strip ─────────────────────────────────────────
  function renderTeams(teams) {
    const card = document.getElementById('lb-teams-card');
    const grid = document.getElementById('lb-teams-grid');
    if (!teams || !teams.length) { card.style.display = 'none'; return; }
    card.style.display = '';
    grid.innerHTML = teams.map(t => {
      const logoHtml = t.logo_url
        ? `<img src="${t.logo_url}" alt="" onerror="this.parentElement.innerHTML='🛡'">`
        : '<span class="lb-team-chip-logo-ph">🛡</span>';
      return `<div class="lb-team-chip">
        <div class="lb-team-chip-logo">${logoHtml}</div>
        <div>
          <div class="lb-team-chip-name">${t.name}</div>
          <div class="lb-team-chip-pts">${fmtPts(t.remaining_points)} left</div>
        </div>
      </div>`;
    }).join('');
  }

  // ── Polling ────────────────────────────────────────────────────
  function poll() {
    fetch('/auction/live-board/data', { cache: 'no-store' })
      .then(r => r.json())
      .then(data => {
        // Apply theme
        if (data.theme) {
          document.documentElement.setAttribute('data-theme', data.theme);
        }

        const p = data.current_player;
        const newId    = p ? p.id    : null;
        const newState = p ? p.state : null;

        // If player changed or state changed (e.g. auction→sold), flash the player panel
        const playerChanged = (newId !== lastPlayerId) || (newState !== lastState);
        if (playerChanged && (lastPlayerId !== null || newId !== null)) {
          const panel = document.getElementById('lb-player-panel');
          panel.style.transition = 'opacity 0.3s';
          panel.style.opacity = '0';
          setTimeout(function() {
            renderPlayer(p);
            renderStatus(p, data.sold_info);
            panel.style.opacity = '1';
          }, 300);
        } else {
          renderPlayer(p);
          renderStatus(p, data.sold_info);
        }

        lastPlayerId = newId;
        lastState    = newState;

        renderHistory(data.recent_history);
        renderTopPlayers(data.top_players || []);
        renderTeams(data.teams);
      })
      .catch(function() {});
  }

  // Initial load + periodic refresh with Page Visibility pause
  var _pollTimer = null;
  function startPolling() { if (!_pollTimer) _pollTimer = setInterval(poll, 4000); }
  function stopPolling()  { if (_pollTimer) { clearInterval(_pollTimer); _pollTimer = null; } }
  document.addEventListener('visibilitychange', function() {
    if (document.hidden) { stopPolling(); }
    else { poll(); startPolling(); }
  });
  window.addEventListener('beforeunload', function() { stopPolling(); clearInterval(_clockTimer); });
  poll();
  startPolling();
})();
